  const normalized = message.toLowerCase();
  if (normalized === 'failed to fetch' || normalized.includes('networkerror')) {
    return copy({
      de: 'Das private Rückspiel konnte nicht erstellt werden.',
      en: 'Could not create the private rematch.',
      pl: 'Nie udało się utworzyć prywatnego rewanżu.',
    });
  }

  return message;
};

import type { KangurDuelLeaderboardEntry, KangurDuelOpponentEntry } from '@kangur/contracts/kangur-duels';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { useMemo, useState } from 'react';

import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import {
  MOBILE_DUEL_DEFAULT_DIFFICULTY,
  MOBILE_DUEL_DEFAULT_OPERATION,
  MOBILE_DUEL_DEFAULT_QUESTION_COUNT,
  MOBILE_DUEL_DEFAULT_TIME_PER_QUESTION_SEC,
} from './mobileDuelDefaults';

type UseKangurMobileLearnerDuelsSummaryOptions = {
  leaderboardLimit: number;
  leaderboardLookbackDays: number;
  opponentsLimit: number;
};

export type UseKangurMobileLearnerDuelsSummaryResult = {
  actionError: string | null;
  createRematch: (opponentLearnerId: string) => Promise<string | null>;
  currentEntry: KangurDuelLeaderboardEntry | null;
  currentRank: number | null;
  error: string | null;
  isActionPending: boolean;
  isAuthenticated: boolean;
  isLoading: boolean;
  isRestoringAuth: boolean;
  opponents: KangurDuelOpponentEntry[];
  pendingOpponentLearnerId: string | null;
  refresh: () => Promise<void>;
};

import { toDuelsSummaryErrorMessage, toDuelsSummaryActionErrorMessage } from './useKangurMobileLearnerDuelsSummary.errors';

export const useKangurMobileLearnerDuelsSummary = ({
  leaderboardLimit,
  leaderboardLookbackDays,
  opponentsLimit,
}: UseKangurMobileLearnerDuelsSummaryOptions): UseKangurMobileLearnerDuelsSummaryResult => {
  const queryClient = useQueryClient();
  const { copy } = useKangurMobileI18n();
  const { apiBaseUrl, apiClient } = useKangurMobileRuntime();
  const { isLoadingAuth, session } = useKangurMobileAuth();
  const [actionError, setActionError] = useState<string | null>(null);
  const [isActionPending, setIsActionPending] = useState(false);
  const [pendingOpponentLearnerId, setPendingOpponentLearnerId] = useState<string | null>(null);
  const learnerIdentity = useMemo(() => 
    session.user?.activeLearner?.id ?? session.user?.email ?? session.user?.id ?? 'guest',
    [session.user]
  );
  const activeLearnerId = session.user?.activeLearner?.id ?? session.user?.id ?? null;
  const isAuthenticated = session.status === 'authenticated';
  const isRestoringAuth = isLoadingAuth && !isAuthenticated;

  const summaryQueries = useMemo(() => ({
    leaderboardQueryKey: [
      'kangur-mobile',
      'duels-summary',
      'leaderboard',
      apiBaseUrl,
      learnerIdentity,
      leaderboardLimit,
      leaderboardLookbackDays,
    ] as const,
    opponentsQueryKey: [
      'kangur-mobile',
      'duels-summary',
      'opponents',
      apiBaseUrl,
      learnerIdentity,
      opponentsLimit,
    ] as const,
  }), [apiBaseUrl, learnerIdentity, leaderboardLimit, leaderboardLookbackDays, opponentsLimit]);

  const leaderboardQuery = useQuery({
    enabled: isAuthenticated,
    queryKey: summaryQueries.leaderboardQueryKey,
    queryFn: async () =>
      apiClient.getDuelLeaderboard(
        {
          limit: leaderboardLimit,
          lookbackDays: leaderboardLookbackDays,
        },
        { cache: 'no-store' },
      ),
    staleTime: 30_000,
  });

  const opponentsQuery = useQuery({
    enabled: isAuthenticated,
    queryKey: summaryQueries.opponentsQueryKey,
    queryFn: async () =>
      apiClient.listDuelOpponents(
        { limit: opponentsLimit },
        { cache: 'no-store' },
      ),
    staleTime: 30_000,
  });

  const leaderboardEntries = leaderboardQuery.data?.entries ?? [];
  const currentRank = activeLearnerId
    ? leaderboardEntries.findIndex((entry) => entry.learnerId === activeLearnerId)
    : -1;
  const currentEntry = currentRank >= 0 ? leaderboardEntries[currentRank] ?? null : null;
  const opponents = useMemo(
    () =>
      [...(opponentsQuery.data?.entries ?? [])]
        .sort((left, right) => Date.parse(right.lastPlayedAt) - Date.parse(left.lastPlayedAt))
        .slice(0, opponentsLimit),
    [opponentsLimit, opponentsQuery.data?.entries],
  );

  return {
    actionError,
    createRematch: async (opponentLearnerId) => {
      setActionError(null);
      setIsActionPending(true);
      setPendingOpponentLearnerId(opponentLearnerId);

      try {
        const response: any = await apiClient.createDuel(
          {
            difficulty: MOBILE_DUEL_DEFAULT_DIFFICULTY,
            mode: 'challenge',
            operation: MOBILE_DUEL_DEFAULT_OPERATION,
            opponentLearnerId,
            questionCount: MOBILE_DUEL_DEFAULT_QUESTION_COUNT,
            timePerQuestionSec: MOBILE_DUEL_DEFAULT_TIME_PER_QUESTION_SEC,
            visibility: 'private',
          },
          { cache: 'no-store' },
        );
        const session = response?.session as { id: string };

        await Promise.all([
          queryClient.invalidateQueries({ queryKey: summaryQueries.leaderboardQueryKey }),
          queryClient.invalidateQueries({ queryKey: summaryQueries.opponentsQueryKey }),
        ]);

        return session?.id ?? null;
      } catch (error: unknown) {

        setActionError(toDuelsSummaryActionErrorMessage(error, copy));
        return null;
      } finally {
        setIsActionPending(false);
        setPendingOpponentLearnerId(null);
      }
    },
    currentEntry,
    currentRank: currentRank >= 0 ? currentRank + 1 : null,
    error:
      toDuelsSummaryErrorMessage(opponentsQuery.error, copy) ??
      toDuelsSummaryErrorMessage(leaderboardQuery.error, copy),
    isActionPending,
    isAuthenticated,
    isLoading: isRestoringAuth || leaderboardQuery.isLoading || opponentsQuery.isLoading,
    isRestoringAuth,
    opponents,
    pendingOpponentLearnerId,
    refresh: async () => {
      await Promise.all([leaderboardQuery.refetch(), opponentsQuery.refetch()]);
    },
  };
};

import type { KangurMobileLocale, KangurMobileLocalizedValue } from '../../i18n/kangurMobileI18n';
import type { 
  KangurDuelStatus, 
  KangurDuelSession, 
  KangurDuelPlayer, 
  KangurDuelSeries,
  KangurDuelPlayerStatus
} from '@kangur/contracts/kangur-duels';
import type { KangurMobileTone as Tone } from '../../shared/KangurMobileUi';
import { DUEL_PLAYER_STATUS_LABELS } from './duels-constants';

export function localizeDuelText(
  value: KangurMobileLocalizedValue<string>,
  locale: KangurMobileLocale,
): string {
  return value[locale];
}

export function localizeSimpleDuelText(
  de: string,
  en: string,
  pl: string,
  locale: KangurMobileLocale,
): string {
  if (locale === 'de') return de;
  if (locale === 'en') return en;
  return pl;
}

export function getLessonMasteryTone(masteryPercent: number): Tone {
  if (masteryPercent >= 90) {
    return {
      backgroundColor: '#ecfdf5',
      borderColor: '#a7f3d0',
      textColor: '#047857',
    };
  }

  if (masteryPercent >= 70) {
    return {
      backgroundColor: '#fffbeb',
      borderColor: '#fde68a',
      textColor: '#b45309',
    };
  }

  return {
    backgroundColor: '#fef2f2',
    borderColor: '#fecaca',
    textColor: '#b91c1c',
  };
}

export function getStatusTone(status: KangurDuelStatus): Tone {
  if (status === 'completed') {
    return {
      backgroundColor: '#ecfdf5',
      borderColor: '#a7f3d0',
      textColor: '#047857',
    };
  }
  if (status === 'aborted') {
    return {
      backgroundColor: '#fef2f2',
      borderColor: '#fecaca',
      textColor: '#b91c1c',
    };
  }
  if (status === 'in_progress' || status === 'ready') {
    return {
      backgroundColor: '#fffbeb',
      borderColor: '#fde68a',
      textColor: '#b45309',
    };
  }

  return {
    backgroundColor: '#eff6ff',
    borderColor: '#bfdbfe',
    textColor: '#1d4ed8',
  };
}

export function getPlayerStatusTone(status: KangurDuelPlayerStatus): Tone {
  if (status === 'completed') {
    return {
      backgroundColor: '#ecfdf5',
      borderColor: '#a7f3d0',
      textColor: '#047857',
    };
  }
  if (status === 'left') {
    return {
      backgroundColor: '#fef2f2',
      borderColor: '#fecaca',
      textColor: '#b91c1c',
    };
  }
  if (status === 'playing') {
    return {
      backgroundColor: '#fffbeb',
      borderColor: '#fde68a',
      textColor: '#b45309',
    };
  }

  return {
    backgroundColor: '#eff6ff',
    borderColor: '#bfdbfe',
    textColor: '#1d4ed8',
  };
}

export function formatPlayerStatusLabel(
  status: KangurDuelPlayerStatus,
  locale: KangurMobileLocale,
): string {
  return localizeDuelText(DUEL_PLAYER_STATUS_LABELS[status], locale);
}

export function resolveSeriesWins(
  series: KangurDuelSeries,
  learnerId: string,
): number {
  return series.winsByPlayer[learnerId] ?? 0;
}

export function formatQuestionProgress(
  session: KangurDuelSession,
  player: KangurDuelPlayer,
  locale: KangurMobileLocale,
): string {
  const completed = Math.min(player.currentQuestionIndex ?? 0, session.questionCount);
  return localizeSimpleDuelText(
    `${completed}/${session.questionCount} Fragen`,
    `${completed}/${session.questionCount} questions`,
    `${completed}/${session.questionCount} pytań`,
    locale,
  );
}

export function formatSpectatorQuestionProgress(
  session: KangurDuelSession,
  locale: KangurMobileLocale,
): string {
  let currentQuestion = session.currentQuestionIndex ?? 0;
  if (session.status === 'in_progress') {
    currentQuestion += 1;
  }
  const displayQuestion = Math.min(currentQuestion, session.questionCount);

  return localizeSimpleDuelText(
    `Runde ${displayQuestion}/${session.questionCount}`,
    `Round ${displayQuestion}/${session.questionCount}`,
    `Runda ${displayQuestion}/${session.questionCount}`,
    locale,
  );
}

export function resolveRoundProgress(
  session: KangurDuelSession,
  player: KangurDuelPlayer | null,
  isSpectating: boolean,
): { total: number; current: number; percent: number } {
  const total = session.questionCount;
  const current = isSpectating
    ? session.currentQuestionIndex ?? 0
    : player?.currentQuestionIndex ?? 0;

  const safeCurrent = Math.min(current, total);
  const percent = total > 0 ? Math.round((safeCurrent / total) * 100) : 0;

  return {
    total,
    current: safeCurrent,
    percent,
  };
}

export function formatRoundProgressLabel(
  progress: { current: number; total: number },
  locale: KangurMobileLocale,
): string {
  const progressText = `${progress.current}/${progress.total}`;
  return localizeSimpleDuelText(
    `Rundenfortschritt ${progressText}`,
    `Round progress ${progressText}`,
    `Postęp rundy ${progressText}`,
    locale,
  );
}

export function formatSeriesTitle(series: KangurDuelSeries, locale: KangurMobileLocale): string {
  const bestOf = (series.bestOf === 3 || series.bestOf === 5 || series.bestOf === 7 || series.bestOf === 9) ? series.bestOf : 1;
  if (bestOf === 1) {
    return localizeDuelText(
      {
        de: 'Einzelnes Match',
        en: 'Single match',
        pl: 'Pojedynczy mecz',
      },
      locale,
    );
  }

  return localizeDuelText(
    {
      de: `BO${bestOf}-Serie`,
      en: `BO${bestOf} series`,
      pl: `Seria BO${bestOf}`,
    },
    locale,
  );
}

export function formatSeriesProgress(
  series: KangurDuelSeries,
  locale: KangurMobileLocale,
): string {
  const gameIndex = Math.min(
    series.bestOf,
    Math.max(1, series.gameIndex),
  );
  return localizeSimpleDuelText(
    `Spiel ${gameIndex} von ${series.bestOf}`,
    `Game ${gameIndex} of ${series.bestOf}`,
    `Gra ${gameIndex} z ${series.bestOf}`,
    locale,
  );
}

export function resolveWinnerSummary(
  players: KangurDuelPlayer[],
  locale: KangurMobileLocale,
): string {
  const defaultSummary = {
    de: 'Das Duell ist beendet.',
    en: 'The duel is finished.',
    pl: 'Pojedynek zakończony.',
  };

  if (players.length === 0) {
    return localizeDuelText(defaultSummary, locale);
  }

  const sorted = [...players].sort((left, right) => {
    const leftScore = left.score + (left.bonusPoints ?? 0);
    const rightScore = right.score + (right.bonusPoints ?? 0);
    return rightScore - leftScore;
  });
  const topPlayer = sorted[0];
  const secondPlayer = sorted[1];

  if (!topPlayer) {
    return localizeDuelText(defaultSummary, locale);
  }

  const topScore = topPlayer.score + (topPlayer.bonusPoints ?? 0);
  const secondScore = secondPlayer !== undefined
    ? secondPlayer.score + (secondPlayer.bonusPoints ?? 0)
    : null;

  if (secondScore !== null && secondScore === topScore) {
    return localizeDuelText(
      {
        de: 'Unentschieden nach der letzten Runde.',
        en: 'Draw after the final round.',
        pl: 'Remis po ostatniej rundzie.',
      },
      locale,
    );
  }

  return localizeSimpleDuelText(
    `${topPlayer.displayName} gewinnt mit ${topScore} Punkten.`,
    `${topPlayer.displayName} wins with ${topScore} points.`,
    `Wygrywa ${topPlayer.displayName} z wynikiem ${topScore}.`,
    locale,
  );
}

import type { KangurDuelStatus, KangurDuelPlayerStatus } from '@kangur/contracts/kangur-duels';
